// Extract apps from the response body
const body = $input.first().json.body;
const apps = Array.isArray(body) ? body : [];

// Also capture the Link header for pagination detection
const headers = $input.first().json.headers || {};
const linkHeader = headers['link'] || headers['Link'] || '';

// Return each app as a separate item for parallel processing
return apps.map(app => ({
  json: {
    appId: app.id,
    appName: app.label,
    appStatus: app.status,
    appSignOnMode: app.signOnMode,
    appCreated: app.created,
    appLastUpdated: app.lastUpdated,
    _linkHeader: linkHeader
  }
}));

// Merge app metadata with the user-count check result
const items = $input.all();

return items.map(item => {
  const body = item.json.body;
  const users = Array.isArray(body) ? body : [];
  const userCount = users.length;

  return {
    json: {
      appId: item.json.appId || $('Split In Batches1').item.json.appId,
      appName: item.json.appName || $('Split In Batches1').item.json.appName,
      appStatus: item.json.appStatus || $('Split In Batches1').item.json.appStatus,
      appSignOnMode: item.json.appSignOnMode || $('Split In Batches1').item.json.appSignOnMode,
      appCreated: item.json.appCreated || $('Split In Batches1').item.json.appCreated,
      hasUsers: userCount > 0,
      userCount: userCount
    }
  };
});

const apps = $input.first().json.appsWithNoUsers || [];
const count = apps.length;
const timestamp = new Date().toISOString();

// Build a clean summary
const rows = apps.map(a =>
  `• ${a.appName} (ID: ${a.appId}) — Status: ${a.appStatus} | Sign-on: ${a.appSignOnMode}`
).join('\n');

const summary = `📋 Okta Apps With No Users Assigned\n` +
  `Generated: ${timestamp}\n` +
  `Total apps found: ${count}\n\n` +
  (count > 0 ? rows : 'All apps have at least one user assigned. ✅');

return [{
  json: {
    summary,
    count,
    timestamp,
    apps
  }
}];
